const $ = (e, t = !1) => t ? document.querySelectorAll(e) : document.querySelector(e);
// $("#year").textContent = (new Date).getFullYear();
let currentSlide = 0;
const totalSlides = 2;

function initializeSlider() {
    const e = document.getElementById("sliderContent"),
        t = document.getElementById("dot1"),
        n = document.getElementById("dot2");
    // if (!e || !t || !n) return void console.error("Slider elements not found");
    if (!e || !t || !n) return;
    t.onclick = function () {
        goToSlide(0)
    }, n.onclick = function () {
        goToSlide(1)
    };
    let i = 0,
        o = 0,
        l = !1;
    e.addEventListener("touchstart", function (e) {
        i = e.touches[0].clientX, l = !0
    }), e.addEventListener("touchmove", function (e) {
        l && (o = e.touches[0].clientX, e.preventDefault())
    }), e.addEventListener("touchend", function () {
        if (!l) return;
        l = !1;
        const e = i - o;
        Math.abs(e) > 50 && (e > 0 && currentSlide < 1 ? nextSlide() : e < 0 && currentSlide > 0 && previousSlide())
    }), updateNavigation()
}

function goToSlide(e) {
    currentSlide = e, updateSlider(), updateNavigation()
}

function nextSlide() {
    currentSlide < 1 && (currentSlide++, updateSlider(), updateNavigation())
}

function previousSlide() {
    currentSlide > 0 && (currentSlide--, updateSlider(), updateNavigation())
}

function updateSlider() {
    const e = document.getElementById("sliderContent");
    if (e) {
        const t = 100 * -currentSlide;
        e.style.transform = "translateX(" + t + "%)"
    }
}

function updateNavigation() {
    const e = document.getElementById("dot1"),
        t = document.getElementById("dot2");
    e && t && (0 === currentSlide ? (e.className = "w-3 h-3 rounded-full bg-blueBrand cursor-pointer transition-all duration-200 hover:scale-110", t.className = "w-3 h-3 rounded-full bg-gray-300 cursor-pointer transition-all duration-200 hover:scale-110") : (e.className = "w-3 h-3 rounded-full bg-gray-300 cursor-pointer transition-all duration-200 hover:scale-110", t.className = "w-3 h-3 rounded-full bg-blueBrand cursor-pointer transition-all duration-200 hover:scale-110"))
}

function toggleAccordion(e) {
    const t = document.getElementById(e),
        n = document.getElementById("icon-" + e),
        i = n.closest("button"),
        o = t.classList.contains("max-h-0") || !t.style.maxHeight || "0px" === t.style.maxHeight;
    if (o) {
        t.classList.remove("max-h-0"), t.classList.remove("max-h-none"),
        t.style.maxHeight = t.scrollHeight + "px";
        n.innerHTML = '<path stroke-linecap="round" stroke-linejoin="round" d="M20 12H4"></path>';
        i.classList.add("border", "border-[#cfcfcf]", "drop-shadow-xl");
    } else {
        t.style.maxHeight = "0px";
        t.classList.add("max-h-0"), t.classList.remove("max-h-none"),
        n.innerHTML = '<path stroke-linecap="round" stroke-linejoin="round" d="M12 4v16m8-8H4"></path>';
        i.classList.remove("border", "border-[#cfcfcf]", "drop-shadow-xl");
    }
}
document.addEventListener("DOMContentLoaded", function () {
        initializeSlider()
    }), window.addEventListener("resize", function () {
        setTimeout(function () {
            initializeSlider()
        }, 100)
    }),
    function () {
        const e = $("#mobile-menu-btn"),
            t = $("#close-menu-btn"),
            n = $("#mobile-menu"),
            i = $("#overlay"),
            o = n.querySelectorAll("a"),
            l = () => {
                n.classList.add("-translate-x-full"), n.classList.remove("translate-x-0"), e.classList.remove("hidden"), i.classList.add("hidden")
            };
        e.addEventListener("click", () => {
            n.classList.remove("-translate-x-full"), n.classList.add("translate-x-0"), e.classList.add("hidden"), i.classList.remove("hidden")
        }), t.addEventListener("click", l), i.addEventListener("click", l), o.forEach(e => {
            e.addEventListener("click", l)
        })
    }();
